class Solution {
    public int[][] validArrangement(int[][] pairs) {
        Map<Integer, List<int[]>> graph = new HashMap<>();
        for (int[] pair : pairs) {
            graph.computeIfAbsent(pair[1], k -> new ArrayList<>()).add(pair);
        }
        List<int[]> res = new ArrayList<>();
        dfs(graph, pairs[0][0], res);
        return res.toArray(new int[0][]);
    }

    private void dfs(Map<Integer, List<int[]>> graph, int node, List<int[]> res) {
        while (graph.containsKey(node) && !graph.get(node).isEmpty()) {
            int[] pair = graph.get(node).remove(0);
            res.add(pair);
            dfs(graph, pair[1], res);
        }
    }
}
